def findMedianSortedArrays(arr1, arr2):
    n = len(arr1)
    low, high = 0, n

    while low <= high:
        partitionX = (low + high) // 2
        partitionY = n - partitionX

        maxLeftX = float('-inf') if partitionX == 0 else arr1[partitionX - 1]
        minRightX = float('inf') if partitionX == n else arr1[partitionX]

        maxLeftY = float('-inf') if partitionY == 0 else arr2[partitionY - 1]
        minRightY = float('inf') if partitionY == n else arr2[partitionY]

        if maxLeftX <= minRightY and maxLeftY <= minRightX:
            if (n % 2 == 0):
                return (max(maxLeftX, maxLeftY) + min(minRightX, minRightY)) / 2
            else:
                return max(maxLeftX, maxLeftY)
        elif maxLeftX > minRightY:
            high = partitionX - 1
        else:
            low = partitionX + 1

def get_median(arr1, arr2):
    n = len(arr1)
    if n != len(arr2) or n == 0:
        return None

    return findMedianSortedArrays(arr1, arr2)

