def find_smallest_missing_number(arr):
    """
    Finds the smallest missing number in a given array.

    Args:
    arr (list): A list of integers where we need to find the smallest missing positive integer.

    Returns:
    int: The smallest missing positive integer from the given array.
    """
    if not arr:
        return 0

    n = len(arr)
    for i in range(n):
        while 1 <= arr[i] <= n and arr[arr[i] - 1] != arr[i]:
            # Swap elements to their correct positions
            arr[arr[i] - 1], arr[i] = arr[i], arr[arr[i] - 1]

    for i in range(n):
        if arr[i] != i + 1:
            return i + 1

    return n + 1

