def maxAverageOfPath(matrix, n):
    if not matrix or n <= 0:
        return (float('-inf'), [])

    dp = [[[float('-inf'), []] for _ in range(n)] for _ in range(n)]
    directions = [(0, -1), (-1, 0), (0, 1), (-1, 1)]

    # Initialize the first row
    for j in range(n):
        dp[0][j] = [matrix[0][j], [(0, j)]]

    # Fill the DP table
    for i in range(1, n):
        for j in range(i + 1):
            if j == 0:
                prev_avg, path = dp[i-1][j][0], dp[i-1][j][1]
                avg = (prev_avg * i + matrix[i][j]) / (i + 1)
                dp[i][j] = [avg, path + [(i, j)] if avg > prev_avg else dp[i-1][j][1]]
            else:
                for dir in directions:
                    x, y = i + dir[0], j + dir[1]
                    if 0 <= x < n and 0 <= y < n:
                        path_length = len(dp[x][y][1]) + 1
                        prev_avg, path = dp[x][y][0], dp[x][y][1] + [(x, y)]
                        avg = (prev_avg * path_length - matrix[i][j]) / path_length
                        if avg > dp[i][j][0]:
                            dp[i][j] = [avg, prev_avg, path]

    return dp[n-1][n-1][0], dp[n-1][n-1][1]

